			snapshot := queueSnapshotFromLifecycle(breakdown)
			result.QueueSnapshot = &snapshot
		}
	}
	if applyStop(work.StopInput{
		NoReadyWork: true,
		Once:        loopMode == executeloop.ModeOnce,
		Mode:        loopMode,
